// Send NPS survey to patients 1-4 hours after appointment completion
const SUPABASE_URL   = 'https://inhyrrjidhzrbqecnptn.supabase.co';
const SERVICE_KEY    = $env.N8N_SUPABASE_SERVICE_KEY;
const CHATWOOT_URL   = 'https://chat.redsolucionesti.com';
const CHATWOOT_TOKEN = 'yypAwZDH2dV3crfbqJqWCgj1';

const hdrs = { 'apikey': SERVICE_KEY, 'Authorization': 'Bearer ' + SERVICE_KEY };

// 1. Get all active clinics
const clinics = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/clinics?select=id,name,chatwoot_account_id&deleted_at=is.null',
    headers: hdrs, json: true
});

if (!Array.isArray(clinics) || clinics.length === 0) {
    return [{ json: { processed: 0 } }];
}

let totalSent = 0;
const results = [];

for (const clinic of clinics) {
    const accountId = clinic.chatwoot_account_id || 2;

    // 2. Get appointments completed 1-4 hours ago that need NPS
    let appointments = [];
    try {
        appointments = await this.helpers.httpRequest({
            method: 'POST',
            url: SUPABASE_URL + '/rest/v1/rpc/get_appointments_for_nps',
            headers: { ...hdrs, 'Content-Type': 'application/json' },
            body: { p_clinic_id: clinic.id },
            json: true
        });
    } catch (e) { appointments = []; }

    if (!Array.isArray(appointments) || appointments.length === 0) continue;

    for (const appt of appointments) {
        // 3. The appointment already has conversation_id from the appointments table
        // Look it up directly
        let convId = null;
        try {
            const apptData = await this.helpers.httpRequest({
                method: 'GET',
                url: SUPABASE_URL + '/rest/v1/appointments?select=conversation_id&id=eq.' + appt.id
                    + '&conversation_id=not.is.null',
                headers: hdrs, json: true
            });
            if (Array.isArray(apptData) && apptData.length > 0) {
                convId = apptData[0].conversation_id;
            }
        } catch (e) { /* skip */ }

        if (!convId) continue;

        const firstName   = (appt.patient_name || 'paciente').split(' ')[0];
        const serviceName = appt.service || 'su consulta';

        const msg = [
            'Hola *' + firstName + '*, gracias por visitarnos en *' + clinic.name + '* 😊',
            '',
            '¿Cómo calificarías tu experiencia con *' + serviceName + '*?',
            '',
            'Por favor responde con un número del *1 al 5*:',
            '1 ⭐ — Muy malo',
            '2 ⭐⭐ — Malo',
            '3 ⭐⭐⭐ — Regular',
            '4 ⭐⭐⭐⭐ — Bueno',
            '5 ⭐⭐⭐⭐⭐ — Excelente',
            '',
            '_Tu opinión nos ayuda a mejorar. ¡Gracias! 🙏_'
        ].join('\n');

        // 4. Send NPS message via Chatwoot
        try {
            await this.helpers.httpRequest({
                method: 'POST',
                url: CHATWOOT_URL + '/api/v1/accounts/' + accountId + '/conversations/' + convId + '/messages',
                headers: { 'api_access_token': CHATWOOT_TOKEN, 'Content-Type': 'application/json' },
                body: { content: msg, message_type: 'outgoing', private: false },
                json: true
            });
        } catch (e) {
            results.push({ appointment_id: appt.id, error: String(e.message) });
            continue;
        }

        // 5. Mark nps_sent = true directly in Supabase
        try {
            await this.helpers.httpRequest({
                method: 'PATCH',
                url: SUPABASE_URL + '/rest/v1/appointments?id=eq.' + appt.id,
                headers: { ...hdrs, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
                body: { nps_sent: true, nps_sent_at: new Date().toISOString() },
                json: true
            });
        } catch (e) { /* non-critical */ }

        totalSent++;
        results.push({ appointment_id: appt.id, patient: appt.patient_name, clinic: clinic.name, sent: true });
    }
}

return [{ json: { processed: totalSent, results } }];
